/**
 * [1.1-API-001] GET /api/bmad-state — HTTP integration tests
 * [1.1-API-002] CORS header assertion
 *
 * TDD Red Phase: these tests define the HTTP contract.
 * They are written to FAIL until the app is wired correctly in the test environment.
 *
 * Strategy: build the express app in isolation (without calling .listen()),
 * wrap it in a node:http server started on port 0 (ephemeral), then use
 * node:http.get to assert the response. Teardown closes the server after each suite.
 */

import { describe, it, expect, vi, beforeAll, afterAll, beforeEach } from "vitest";
import http from "node:http";
import express from "express";
import cors from "cors";
import helmet from "helmet";

// ─── Mocks ────────────────────────────────────────────────────────────────────
// Mock config before any other server module is imported, so the module-level
// side-effects in config.js (fs.existsSync, process.cwd) do not run against
// the real filesystem during tests.
vi.mock("../config.js", () => ({
  packageRoot: "/fake/package",
  isRunAsPackage: false,
  projectRoot: "/fake/project",
  bmadRoot: "/fake/project/_bmad",
}));

// Mock fileWatch.js — subscribe/startWatching have side effects (fs.watch calls)
vi.mock("../fileWatch.js", () => ({
  subscribe: vi.fn(() => vi.fn()),
  startWatching: vi.fn(),
}));

// Mock the heavy I/O functions so the endpoint can respond without a real FS
vi.mock("../fileUtils.js", async (importOriginal) => {
  const actual = await importOriginal();
  return {
    ...actual,
    loadYaml: vi.fn(),
    loadCsv: vi.fn(),
  };
});

vi.mock("../bmadState.js", async (importOriginal) => {
  const actual = await importOriginal();
  return {
    ...actual,
    getBmmConfig: vi.fn(),
    detectArtifacts: vi.fn(),
    getSprintStatus: vi.fn(),
  };
});

vi.mock("../artifactDetails.js", () => ({
  getArtifactDetails: vi.fn(),
}));

// ─── Helpers ──────────────────────────────────────────────────────────────────
/** Start the express app on an ephemeral port. Returns { server, url, close }. */
async function startTestServer() {
  const { registerRoutes } = await import("../routes.js");
  const app = express();
  app.use(helmet());
  app.use(cors({ origin: /^https?:\/\/localhost(:\d+)?$/ }));
  registerRoutes(app);

  return new Promise((resolve) => {
    const server = http.createServer(app);
    server.listen(0, "127.0.0.1", () => {
      const { port } = server.address();
      resolve({
        server,
        url: `http://127.0.0.1:${port}`,
        close: () => new Promise((res) => server.close(res)),
      });
    });
  });
}

/** Make a GET request and return { status, headers, body } */
function get(url, reqHeaders = {}) {
  return new Promise((resolve, reject) => {
    http
      .get(url, { headers: reqHeaders }, (res) => {
        let data = "";
        res.on("data", (chunk) => (data += chunk));
        res.on("end", () =>
          resolve({ status: res.statusCode, headers: res.headers, body: data }),
        );
      })
      .on("error", reject);
  });
}

// ─── Test Suite ───────────────────────────────────────────────────────────────
describe("[1.1-API-001] GET /api/bmad-state", () => {
  let ctx;
  let fileUtilsMod;
  let bmadStateMod;
  let artifactDetailsMod;

  beforeAll(async () => {
    fileUtilsMod = await import("../fileUtils.js");
    bmadStateMod = await import("../bmadState.js");
    artifactDetailsMod = await import("../artifactDetails.js");
    ctx = await startTestServer();
  });

  afterAll(async () => {
    await ctx.close();
  });

  beforeEach(() => {
    vi.resetAllMocks();

    // Default happy-path stubs
    fileUtilsMod.loadYaml.mockResolvedValue({ installation: "local", modules: ["bmm"] });
    fileUtilsMod.loadCsv.mockResolvedValue([]);
    bmadStateMod.getBmmConfig.mockResolvedValue({
      project_name: "TestProject",
      planning_artifacts: "/fake/project/_bmad-output/planning-artifacts",
      implementation_artifacts: "/fake/project/_bmad-output/implementation-artifacts",
    });
    bmadStateMod.detectArtifacts.mockResolvedValue({
      hasPrd: false,
      hasArchitecture: false,
      hasEpics: false,
      hasUx: false,
      hasSprintStatus: false,
      storyFiles: [],
    });
    bmadStateMod.getSprintStatus.mockResolvedValue(null);
    artifactDetailsMod.getArtifactDetails.mockResolvedValue(null);
  });

  it("[P1] returns HTTP 200", async () => {
    const { status } = await get(`${ctx.url}/api/bmad-state`);
    expect(status).toBe(200);
  });

  it("[P1] responds with Content-Type application/json", async () => {
    const { headers } = await get(`${ctx.url}/api/bmad-state`);
    expect(headers["content-type"]).toMatch(/application\/json/);
  });

  it("[P1] response body contains required top-level keys: projectName, phase, artifacts, nextSteps", async () => {
    const { body } = await get(`${ctx.url}/api/bmad-state`);
    const data = JSON.parse(body);
    expect(data).toHaveProperty("projectName");
    expect(data).toHaveProperty("phase");
    expect(data).toHaveProperty("artifacts");
    expect(data).toHaveProperty("nextSteps");
  });

  it("[P1] projectName reflects value from getBmmConfig", async () => {
    const { body } = await get(`${ctx.url}/api/bmad-state`);
    const data = JSON.parse(body);
    expect(data.projectName).toBe("TestProject");
  });

  it("[P1] phase is a non-empty string", async () => {
    const { body } = await get(`${ctx.url}/api/bmad-state`);
    const data = JSON.parse(body);
    expect(typeof data.phase).toBe("string");
    expect(data.phase.length).toBeGreaterThan(0);
  });

  it("[P1] nextSteps is an array", async () => {
    const { body } = await get(`${ctx.url}/api/bmad-state`);
    const data = JSON.parse(body);
    expect(Array.isArray(data.nextSteps)).toBe(true);
  });

  it("[P1] artifacts is an object with boolean artifact flags", async () => {
    bmadStateMod.detectArtifacts.mockResolvedValue({
      hasPrd: true,
      hasArchitecture: false,
      hasEpics: false,
      hasUx: false,
      hasSprintStatus: false,
      storyFiles: [],
    });
    const { body } = await get(`${ctx.url}/api/bmad-state`);
    const data = JSON.parse(body);
    expect(typeof data.artifacts).toBe("object");
    expect(data.artifacts.hasPrd).toBe(true);
    expect(data.artifacts.hasArchitecture).toBe(false);
  });

  it("[P1] returns 500 with error JSON when getBmmConfig throws", async () => {
    bmadStateMod.getBmmConfig.mockRejectedValue(new Error("config load failure"));
    const { status, body } = await get(`${ctx.url}/api/bmad-state`);
    expect(status).toBe(500);
    const data = JSON.parse(body);
    expect(data).toHaveProperty("error");
  });
});

describe("[1.1-API-002] CORS headers", () => {
  let ctx;

  beforeAll(async () => {
    ctx = await startTestServer();
  });

  afterAll(async () => {
    await ctx.close();
  });

  it("[P1] includes Access-Control-Allow-Origin for localhost origin", async () => {
    const { headers } = await get(
      `${ctx.url}/api/bmad-state`,
      { Origin: "http://localhost:5173" },
    );
    expect(headers["access-control-allow-origin"]).toBeDefined();
  });

  it("[P1] does not include Access-Control-Allow-Origin for non-localhost origin", async () => {
    const { headers } = await get(
      `${ctx.url}/api/bmad-state`,
      { Origin: "http://evil.example.com" },
    );
    // cors() with the localhost-only regex should NOT set the header for external origins
    expect(headers["access-control-allow-origin"]).toBeUndefined();
  });
});
